<template><el-card shadow="never"><el-table :data="rows" v-loading="loading" size="small" border><el-table-column prop="id" label="ID" width="70" /><el-table-column prop="asset_code" label="资产编号" min-width="160" /><el-table-column prop="sn" label="SN" min-width="140" /><el-table-column label="型号" min-width="200"><template #default="{ row }"><span>{{ [row.brand, row.model].filter(Boolean).join(' ') }}</span></template></el-table-column><el-table-column prop="size_inch" label="尺寸" width="90" /><el-table-column label="状态" width="110"><template #default="{ row }">{{ statusText(row.status) }}</template></el-table-column><el-table-column label="位置" min-width="180"><template #default="{ row }">{{ locationText(row) }}</template></el-table-column><el-table-column label="领用人" min-width="180"><template #default="{ row }"><span v-if="row.employee_no || row.employee_name">{{ row.employee_name }}（{{ row.employee_no }}）</span><span v-else>-</span></template></el-table-column><el-table-column prop="department" label="部门" min-width="140" /><el-table-column prop="updated_at" label="更新时间" min-width="170" /><el-table-column label="操作" width="220" fixed="right"><template #default="{ row }"><div class="monitor-op-group compact"><el-button v-if="canOperator" link type="success" @click="emit('in', row)">入库</el-button><el-button v-if="canOperator" link type="warning" @click="emit('out', row)">出库</el-button><el-dropdown v-if="canOperator || isAdmin" trigger="click" @command="(command: string | number | object) => emit('row-more', String(command), row)"><el-button link class="row-more-trigger">更多<el-icon class="el-icon--right"><ArrowDown /></el-icon></el-button><template #dropdown><el-dropdown-menu><el-dropdown-item v-if="isAdmin" command="edit">编辑</el-dropdown-item><el-dropdown-item v-if="canOperator" command="qr">二维码</el-dropdown-item><el-dropdown-item v-if="canOperator" command="return">归还</el-dropdown-item><el-dropdown-item v-if="canOperator" command="transfer">调拨</el-dropdown-item><el-dropdown-item v-if="isAdmin" command="delete" divided>删除</el-dropdown-item></el-dropdown-menu></template></el-dropdown></div></template></el-table-column></el-table><div class="pager-wrap"><el-pagination background layout="total, sizes, prev, pager, next" :total="total" :page-size="pageSize" :current-page="page" @update:page-size="(value: number) => emit('size-change', value)" @update:current-page="(value: number) => emit('page-change', value)" /></div></el-card></template>
<script setup lang="ts">import { ArrowDown } from '@element-plus/icons-vue'; defineProps<{ rows:Array<Record<string,any>>; loading:boolean; total:number; page:number; pageSize:number; canOperator:boolean; isAdmin:boolean; statusText:(status:string)=>string; locationText:(row:Record<string,any>)=>string }>(); const emit = defineEmits<{ in:[Record<string,any>]; out:[Record<string,any>]; 'row-more':[string,Record<string,any>]; 'page-change':[number]; 'size-change':[number] }>();</script>
<style scoped>.pager-wrap{margin-top:12px;display:flex;justify-content:flex-end}.monitor-op-group.compact{display:flex;align-items:center;gap:8px}</style>
